eval_calls:
() => {
                    window.__spy_reading = true;
                    const data = {
                        eval_calls:       window.__spy.eval_calls,
                        dom_writes:       window.__spy.dom_writes,
                        popups:           window.__spy.popups,
                        form_submissions: window.__spy.form_submissions,
                    };
                    window.__spy_reading = false;
                    return data;
                }
